dashboard.definition:
{
    "title": "Server",
    "description": "Gain comprehensive insights into network performance including utilization and error rates for Server related Network Objects within IMM, Standalone and Unified Edge targets. This dashboard leverages both Inventory and Network Metrics data sources to deliver a unified, correlated view of network health and performance across your infrastructure.",
    "inputs": {
        "input_bDtDrWq5": {
            "options": {
                "defaultValue": "-24h@h,now",
                "token": "time_range"
            },
            "title": "Select Time Range",
            "type": "input.timerange"
        },
        "input_bHm9kw35": {
            "options": {
                "defaultValue": "timechart",
                "items": [
                    {
                        "label": "Auto",
                        "value": "timechart"
                    },
                    {
                        "label": "15 Minutes",
                        "value": "timechart span=15m"
                    },
                    {
                        "label": "30 Minutes",
                        "value": "timechart span=30m"
                    },
                    {
                        "label": "1 Hour",
                        "value": "timechart span=1h"
                    }
                ],
                "token": "granularity"
            },
            "title": "Granularity for Linecharts",
            "type": "input.dropdown"
        },
        "input_chassisSelect": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": ">statics | formatByType(formattedConfig)",
                "label": ">primary | seriesByName(\"chassis_name\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": ">primary | seriesByName(\"Chassis\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_LU3nqIRB"
            },
            "options": {
                "defaultValue": "*",
                "items": ">frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "select_chassis"
            },
            "title": "Select Chassis",
            "type": "input.multiselect"
        },
        "input_dZ3m6CzQ": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": ">statics | formatByType(formattedConfig)",
                "label": ">primary | seriesByName(\"account_name\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": ">primary | seriesByName(\"account_name\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_NJS3k4KJ"
            },
            "options": {
                "defaultValue": "*",
                "items": ">frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "account_name"
            },
            "title": "Intersight Account Name",
            "type": "input.dropdown"
        },
        "input_domainSelect": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": "> statics | formatByType(formattedConfig)",
                "label": "> primary | seriesByName(\"event.DomainName\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": "> primary | seriesByName(\"event.DomainId\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_MRht5eW9"
            },
            "options": {
                "defaultValue": [
                    "*"
                ],
                "items": "> frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "select_domain"
            },
            "title": "Select Domains",
            "type": "input.multiselect"
        },
        "input_gYZyvcok": {
            "options": {
                "defaultValue": "MB",
                "items": [
                    {
                        "label": "KB",
                        "value": "KB"
                    },
                    {
                        "label": "MB",
                        "value": "MB"
                    },
                    {
                        "label": "GB",
                        "value": "GB"
                    },
                    {
                        "label": "TB",
                        "value": "TB"
                    }
                ],
                "token": "data_unit_transmit"
            },
            "title": "Ethernet Transmit per Server - Data Unit",
            "type": "input.dropdown"
        },
        "input_ontNWqiw": {
            "options": {
                "defaultValue": "*",
                "prefix": "*",
                "suffix": "*",
                "token": "errors_port_name_server"
            },
            "title": "Port Name",
            "type": "input.text"
        },
        "input_serverSelect": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": "> statics | formatByType(formattedConfig)",
                "label": "> primary | seriesByName(\"Name\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": "> primary | seriesByName(\"server_moid\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_cGpElpVV"
            },
            "options": {
                "defaultValue": "*",
                "items": "> frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "select_server"
            },
            "title": "Select Server Profile",
            "type": "input.multiselect"
        },
        "input_tDQb5avh": {
            "options": {
                "defaultValue": "MB",
                "items": [
                    {
                        "label": "KB",
                        "value": "KB"
                    },
                    {
                        "label": "MB",
                        "value": "MB"
                    },
                    {
                        "label": "GB",
                        "value": "GB"
                    },
                    {
                        "label": "TB",
                        "value": "TB"
                    }
                ],
                "token": "data_unit_receive"
            },
            "title": "Ethernet Receive per Server - Data Unit",
            "type": "input.dropdown"
        },
        "input_uZmhqshU": {
            "context": {},
            "dataSources": {},
            "options": {
                "defaultValue": "false",
                "items": [
                    {
                        "label": "Exclude zero values",
                        "value": "false"
                    },
                    {
                        "label": "Include zero values",
                        "value": "true"
                    }
                ],
                "token": "show_zero_values"
            },
            "title": "",
            "type": "input.dropdown"
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {}
                }
            }
        }
    },
    "visualizations": {
        "viz_1GPTAfGC": {
            "dataSources": {
                "primary": "ds_1KbbTelR"
            },
            "description": "This panel displays the total Fibre Channel (FC) receive utilization per server for vhba ports, It uses the io_receive sum aggregation metric to help identify servers with high FC traffic, assisting in storage or SAN-related performance analysis and troubleshooting.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._hwServerId.value",
                                "token": "clicked_server_fc_receive"
                            },
                            {
                                "key": "row.Server Profile Name.value",
                                "token": "clicked_server_fc_receive_name"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "drilldown": "cell",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "FC Receive utilization per Server (Sum)",
            "type": "splunk.table"
        },
        "viz_21eaI7WA": {
            "dataSources": {
                "primary": "ds_wa0bh2Om"
            },
            "hideWhenNoData": true,
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "showRoundedY2AxisLabels": false,
                "showY2MajorGridLines": true,
                "y2AxisAbbreviation": "off",
                "yAxisAbbreviation": "off",
                "yAxisTitleText": "MB"
            },
            "showProgressBar": true,
            "title": "FC Transmit utilization per Server (Sum): $clicked_server_fc_transmit_name$",
            "type": "splunk.line"
        },
        "viz_6WZIyONZ": {
            "dataSources": {
                "primary": "ds_IBNSrkeX"
            },
            "description": "",
            "hideWhenNoData": true,
            "options": {
                "count": 5,
                "drilldown": "none",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Ethernet Transmit utilization per Server (Sum): $eth_transmit_util_server$",
            "type": "splunk.table"
        },
        "viz_7VXWSSim": {
            "dataSources": {
                "primary": "ds_mwh93x7o"
            },
            "hideWhenNoData": true,
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "showRoundedY2AxisLabels": false,
                "showY2MajorGridLines": true,
                "y2AxisAbbreviation": "off",
                "yAxisAbbreviation": "off",
                "yAxisTitleText": "MB"
            },
            "showProgressBar": true,
            "title": "FC Receive utilization per Server (Sum): $clicked_server_fc_receive_name$",
            "type": "splunk.line"
        },
        "viz_A8foL1YL": {
            "dataSources": {
                "primary": "ds_oPXoFMwJ"
            },
            "description": "This panel displays the total Ethernet transmit utilization per server, using the network_io_transmit metric. It helps identify server-wise outbound traffic patterns, providing insights into network load distribution and potential hotspots across connected servers.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row.Server Name.value",
                                "token": "eth_transmit_util_server"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "showRoundedY2AxisLabels": false,
                "showSplitSeries": false,
                "showY2MajorGridLines": true,
                "y2AxisAbbreviation": "off",
                "yAxisAbbreviation": "off"
            },
            "showProgressBar": true,
            "title": "Ethernet Transmit utilization per Server (Sum)",
            "type": "splunk.bar"
        },
        "viz_DcbtlWMG": {
