                "yAxisAbbreviation": "off",
                "yAxisTitleText": "MB"
            },
            "showProgressBar": true,
            "title": "Ethernet Transmit utilization per Server (Sum): $clicked_server_ethernet_transmit_name$",
            "type": "splunk.line"
        },
        "viz_hcas8rDQ": {
            "dataSources": {
                "primary": "ds_esN0ocsU"
            },
            "description": "This panel displays the total Ethernet receive utilization per server, using the network_io_receive metric. It helps identify server-wise outbound traffic patterns, providing insights into network load distribution and potential hotspots across connected servers.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row.Server Name.value",
                                "token": "eth_receive_util_server"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "showRoundedY2AxisLabels": false,
                "showY2MajorGridLines": true,
