                "yAxisAbbreviation": "off"
            },
            "showProgressBar": true,
            "title": "Ethernet Receive utilization per Server (Sum)",
            "type": "splunk.bar"
        },
        "viz_jZWIdnRK": {
            "dataSources": {
                "primary": "ds_6JSIWZfk"
            },
            "description": "This panel displays the total Fibre Channel (FC) transmit utilization per server for vhba ports, It uses the io_transmit sum aggregation metric to help identify servers with high FC traffic, assisting in storage or SAN-related performance analysis and troubleshooting.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._hwServerId.value",
                                "token": "clicked_server_fc_transmit"
                            },
                            {
                                "key": "row.Server Profile Name.value",
                                "token": "clicked_server_fc_transmit_name"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
