            },
            "showProgressBar": true,
            "title": "FC Transmit utilization per Server (Sum)",
            "type": "splunk.table"
        },
        "viz_lcc9J1pS": {
            "dataSources": {
                "primary": "ds_Zj7P7pQj"
            },
            "hideWhenNoData": true,
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "showRoundedY2AxisLabels": false,
                "showY2MajorGridLines": true,
                "xAxisLabelRotation": -45,
                "xAxisTitleText": "Timestamp",
                "xAxisTitleVisibility": "hide",
                "y2AxisAbbreviation": "off",
                "yAxisAbbreviation": "off",
                "yAxisTitleText": "KB",
                "yAxisTitleVisibility": "hide"
            },
            "showProgressBar": true,
            "title": "Errors per selected port: '$clicked_errors_name_server$'",
            "type": "splunk.line"
        },
        "viz_u0sR9FSx": {
            "dataSources": {
                "primary": "ds_iIZs1sJ1"
            },
            "description": "This panel provides an overview of server-related network errors, It displays key error metrics like Total Errors, CRC, Runt, Jabber, Transmit/Receive Errors, and more, helping to identify potential connectivity or hardware issues at the server port level.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._event_id.value",
                                "token": "clicked_errors_server"
                            },
                            {
                                "key": "row.Port Name.value",
                                "token": "clicked_errors_name_server"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "drilldown": "row",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Errors - Overview",
            "type": "splunk.table"
        },
        "viz_zRZOqW2Q": {
            "dataSources": {
                "primary": "ds_DCHhSUtZ"
            },
            "description": "This panel shows the total Ethernet transmit utilization per server of vnic ports using the io_transmit sum aggregation metric. It helps identify servers generating high outbound traffic, supporting troubleshooting of network load distribution and potential congestion in server-level communications.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._hwServerId.value",
                                "token": "clicked_server_ethernet_transmit"
                            },
                            {
                                "key": "row.Server Profile Name.value",
                                "token": "clicked_server_ethernet_transmit_name"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "drilldown": "cell",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Ethernet Transmit utilization per Server (Sum)",
            "type": "splunk.table"
        }
    },
    "dataSources": {
        "ds_1KbbTelR": {
            "name": "FC Receive utilization per Server _Sum_ search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_io_receive_ag) as total_nirsag\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n        AND cisco_intersight.cisco_intersight_network.network_server_id=*\n        AND cisco_intersight.cisco_intersight_network.network_port_role=\"vhba\"\n    by \n        cisco_intersight.cisco_intersight_network.network_domain_id,\n        cisco_intersight.cisco_intersight_network.network_domain_name,\n        cisco_intersight.cisco_intersight_network.network_chassis,\n        cisco_intersight.cisco_intersight_network.network_chassis_number,\n        cisco_intersight.cisco_intersight_network.network_server_id,\n        cisco_intersight.cisco_intersight_network.network_host_name,\n        cisco_intersight.cisco_intersight_network.network_name,\n        cisco_intersight.cisco_intersight_network.network_port_role,\n        cisco_intersight.cisco_intersight_network.network_account_moid,\n        cisco_intersight.cisco_intersight_network.network_id, cisco_intersight.cisco_intersight_network.network_account_name\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \".*/(?<server_id>[^/]+)$\"\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id server_name\n]\n\n| join type=left server_id [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_profile_name by AssignedServer.Moid\n    | rename AssignedServer.Moid as server_id\n    | table server_id server_profile_name\n]\n\n| rex field=cisco_intersight.cisco_intersight_network.network_host_name \"FI-(?<FI>[AB])\"\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_id\" \"/(?<Moid>[^/]+)$\"\n| eval _key='cisco_intersight.cisco_intersight_network.network_account_moid' + \"_\" + Moid\n\n| appendpipe [\n| join type=left _key [\n| inputlookup cisco_intersight_adapter_hostfcinterfaces | where splunk_managed_lifecycle == \"PRESENT\" \n   | rename \"Vfc.Moid\" AS vfc_Moid\n   | join type=left vfc_Moid\n    [| inputlookup cisco_intersight_network_vfcs | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS vfc_Moid\n    | rename NetworkElement.Moid as network_moid\n    | rename PinnedInterface.Moid as physical_port_moid\n    | rename BoundInterface.Moid as portchannel_moid\n    | table network_moid, vfc_Moid, physical_port_moid, portchannel_moid\n    ]\n   | join type=left network_moid \n    [| inputlookup cisco_intersight_network_elements | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS network_moid \n    | table SwitchId, network_moid\n    ]\n   | join type=left physical_port_moid \n    [| inputlookup cisco_intersight_fc_physicalports | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS physical_port_moid\n    | rename PortId AS \"PhysicalPortId\", SlotId as \"PhysicalSlotId\"\n    | table physical_port_moid, PhysicalPortId, PhysicalSlotId, OperSpeed\n    ]\n   | join type=left portchannel_moid\n   [| inputlookup cisco_intersight_ether_portchannels | where splunk_managed_lifecycle == \"PRESENT\"\n   | rename Moid as portchannel_moid\n   | table PortChannelId, portchannel_moid\n   ]\n| eval IOM_Host_Interface=if(isnotnull(PortChannelId), \"PC-\" + PortChannelId, null())\n| eval FI_Uplink = 'PhysicalSlotId' + \"/\" + 'PhysicalPortId'\n| eval Virtual_Circuit=VifId\n| dedup Virtual_Circuit\n| table _key, PortId, Dn, OperState, PortChannelId, Role, SwitchId, Virtual_Circuit, OperState, PhysicalPortId, PortChannelId, FI_Uplink, IOM_Host_Interface, OperSpeed\n]\n]\n\n| where \"$show_zero_values$\"=\"true\" OR (total_nirsag != 0)\n\n| eval Utilization = `cisco_intersight_human_readable_bytes(total_nirsag)`.\" \".`cisco_intersight_human_readable_unit(total_nirsag)`\n| rename server_name as \"Server Name\", \n         cisco_intersight.cisco_intersight_network.network_chassis_number as \"Chassis Number\", \n         cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\", \n         server_profile_name as \"Server Profile Name\", \n         cisco_intersight.cisco_intersight_network.network_server_id as _hwServerId,\n         cisco_intersight.cisco_intersight_network.network_name as Name,\n         cisco_intersight.cisco_intersight_network.network_port_role as \"Port Role\", SwitchId as FI\n\n| where isnotnull(Virtual_Circuit) OR isnotnull(FI_Uplink) OR isnotnull(IOM_Host_Interface)\n\n| table \"Domain Name\", FI, \"Chassis Number\", \"Server Profile Name\", \"Server Name\", Name, Utilization, Dn, OperState, OperSpeed, Virtual_Circuit, OperState, FI_Uplink, IOM_Host_Interface, _hwServerId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_6JSIWZfk": {
            "name": "FC Transmit utilization per Server _Sum_ search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_io_transmit_ag) as total_nitsag\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n        AND cisco_intersight.cisco_intersight_network.network_server_id=*\n        AND cisco_intersight.cisco_intersight_network.network_port_role=\"vhba\"\n    by \n        cisco_intersight.cisco_intersight_network.network_domain_id,\n        cisco_intersight.cisco_intersight_network.network_domain_name,\n        cisco_intersight.cisco_intersight_network.network_chassis,\n        cisco_intersight.cisco_intersight_network.network_chassis_number,\n        cisco_intersight.cisco_intersight_network.network_server_id,\n        cisco_intersight.cisco_intersight_network.network_host_name,\n        cisco_intersight.cisco_intersight_network.network_name,\n        cisco_intersight.cisco_intersight_network.network_port_role,\n        cisco_intersight.cisco_intersight_network.network_account_moid,\n        cisco_intersight.cisco_intersight_network.network_id, cisco_intersight.cisco_intersight_network.network_account_name\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \"/(?<server_object_type>[^/]+)/(?<server_id>[^/]+)$\"\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id server_name\n]\n\n| join type=left server_id [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_profile_name by AssignedServer.Moid\n    | rename AssignedServer.Moid as server_id\n    | table server_id server_profile_name\n]\n\n| rex field=cisco_intersight.cisco_intersight_network.network_host_name \"FI-(?<FI>[AB])\"\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_id\" \"/(?<Moid>[^/]+)$\"\n| eval _key='cisco_intersight.cisco_intersight_network.network_account_moid' + \"_\" + Moid\n\n| appendpipe [\n| join type=left _key [\n| inputlookup cisco_intersight_adapter_hostfcinterfaces | where splunk_managed_lifecycle == \"PRESENT\" \n   | rename \"Vfc.Moid\" AS vfc_Moid\n   | join type=left vfc_Moid\n    [| inputlookup cisco_intersight_network_vfcs | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS vfc_Moid\n    | rename NetworkElement.Moid as network_moid\n    | rename PinnedInterface.Moid as physical_port_moid\n    | rename BoundInterface.Moid as portchannel_moid\n    | table network_moid, vfc_Moid, physical_port_moid, portchannel_moid\n    ]\n   | join type=left network_moid \n    [| inputlookup cisco_intersight_network_elements | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS network_moid \n    | table SwitchId, network_moid\n    ]\n   | join type=left physical_port_moid \n    [| inputlookup cisco_intersight_fc_physicalports | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS physical_port_moid\n    | rename PortId AS \"PhysicalPortId\", SlotId as \"PhysicalSlotId\"\n    | table physical_port_moid, PhysicalPortId, PhysicalSlotId, OperSpeed\n    ]\n   | join type=left portchannel_moid\n   [| inputlookup cisco_intersight_ether_portchannels | where splunk_managed_lifecycle == \"PRESENT\"\n   | rename Moid as portchannel_moid\n   | table PortChannelId, portchannel_moid\n   ]\n| eval IOM_Host_Interface=if(isnotnull(PortChannelId), \"PC-\" + PortChannelId, null())\n| eval FI_Uplink = 'PhysicalSlotId' + \"/\" + 'PhysicalPortId'\n| eval Virtual_Circuit=VifId\n| dedup Virtual_Circuit\n| table _key, PortId, Dn, OperState, PortChannelId, Role, SwitchId, Virtual_Circuit, OperState, PhysicalPortId, PortChannelId, FI_Uplink, IOM_Host_Interface, OperSpeed\n]\n]\n\n| where \"$show_zero_values$\"=\"true\" OR (total_nitsag != 0)\n\n| eval Utilization = `cisco_intersight_human_readable_bytes(total_nitsag)`.\" \".`cisco_intersight_human_readable_unit(total_nitsag)`\n| rename server_name as \"Server Name\", \n         cisco_intersight.cisco_intersight_network.network_chassis_number as \"Chassis Number\", \n         cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\", \n         server_profile_name as \"Server Profile Name\", \n         cisco_intersight.cisco_intersight_network.network_server_id as _hwServerId,\n         cisco_intersight.cisco_intersight_network.network_name as Name,\n         cisco_intersight.cisco_intersight_network.network_port_role as \"Port Role\", SwitchId as FI\n\n| where isnotnull(Virtual_Circuit) OR isnotnull(FI_Uplink) OR isnotnull(IOM_Host_Interface)\n\n| table \"Domain Name\", FI, \"Chassis Number\", \"Server Profile Name\", \"Server Name\", Name, Utilization, Dn, OperState, OperSpeed, Virtual_Circuit, OperState, FI_Uplink, IOM_Host_Interface, _hwServerId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_DCHhSUtZ": {
            "name": "Ethernet Transmit utilization per Server _Sum_ 2 search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_io_transmit_ag) as total_nitsag\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n        AND cisco_intersight.cisco_intersight_network.network_server_id=*\n        AND cisco_intersight.cisco_intersight_network.network_port_role = \"vnic\"\n    by \n        cisco_intersight.cisco_intersight_network.network_domain_id,\n        cisco_intersight.cisco_intersight_network.network_domain_name,\n        cisco_intersight.cisco_intersight_network.network_chassis,\n        cisco_intersight.cisco_intersight_network.network_chassis_number,\n        cisco_intersight.cisco_intersight_network.network_server_id,\n        cisco_intersight.cisco_intersight_network.network_host_name\n        cisco_intersight.cisco_intersight_network.network_name,\n        cisco_intersight.cisco_intersight_network.network_port_role,\n        cisco_intersight.cisco_intersight_network.network_account_moid,\n        cisco_intersight.cisco_intersight_network.network_id, \n        cisco_intersight.cisco_intersight_network.network_account_name\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \"/(?<server_object_type>[^/]+)/(?<server_id>[^/]+)$\"\n\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\"\n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id, server_name, Model, PlatformType\n]\n\n| join type=left server_id [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" | stats values(Name) as server_profile_name by AssignedServer.Moid\n    | rename AssignedServer.Moid as server_id\n    | table server_id server_profile_name\n]\n\n| rex field=cisco_intersight.cisco_intersight_network.network_host_name \"FI-(?<FI>[AB])\"\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_id\" \"/(?<Moid>[^/]+)$\"\n| eval _key='cisco_intersight.cisco_intersight_network.network_account_moid' + \"_\" + Moid\n\n| appendpipe [\n    | where lower(server_object_type) = \"blades\"\n| join type=left _key [\n    | inputlookup cisco_intersight_adapter_hostethinterfaces | where splunk_managed_lifecycle == \"PRESENT\" \n| mvexpand AdapterUnit.ExtEthIfs.Parent.Moid \n| rename \"AdapterUnit.ExtEthIfs.Parent.Moid\" AS \"IoCard_Moid\" \n| rename Name AS VNIC \n| eval FI_Uplink = if(\n       isnotnull('Vethernet.PinnedInterface.SlotId') AND isnotnull('Vethernet.PinnedInterface.PortId'),\n       'Vethernet.PinnedInterface.SlotId' . \"/\" . 'Vethernet.PinnedInterface.PortId',\n       mvindex(split('Vethernet.PinnedInterfaceDn', \"/\"), -1)\n    )\n| join type=left IoCard_Moid\n    [| inputlookup cisco_intersight_equipment_iocards | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS IoCard_Moid \n    | mvexpand \"NetworkPorts.NetworkPorts.Moid\" \n    | rename \"NetworkPorts.NetworkPorts.Moid\" as NetworkPortMoid]\n| join type=left NetworkPortMoid \n    [| inputlookup cisco_intersight_ether_networkports | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid AS NetworkPortMoid \n    | rename \"AcknowledgedPeerInterface.Moid\" AS Physical_Port_Moid ]\n| join type=left Physical_Port_Moid \n    [| inputlookup cisco_intersight_ether_physicalports | where splunk_managed_lifecycle == \"PRESENT\" \n    | rename Moid as \"Physical_Port_Moid\" \n    | rename PortId AS \"PhysicalPortId\" \n    | rename PortChannelId as \"PhysicalPortChannelId\"]\n| eval Virtual_Circuit=VifId \n| eval Network_Adapter='AdapterUnit.AdapterId' \n| eval IOM_Host_Interface=if(IOMHostInterfaces != \"\", \"PC-\" + IOMHostInterfaces, null())\n| eval FC_Server_Interface=if(isnotnull(PhysicalPortChannelId), \"PC-\" + PhysicalPortChannelId, null())\n| dedup VNIC, Virtual_Circuit \n| table _key, PortId, Dn, OperSpeed, OperState, PortChannelId, Role, SwitchId, VNIC, Virtual_Circuit, Network_Adapter, OperState, FI_Uplink, IOM_Host_Interface, FC_Server_Interface\n]\n]\n\n| appendpipe [\n    | where lower(server_object_type) = \"rackunits\"\n| join type=left _key [\n    | inputlookup cisco_intersight_adapter_hostethinterfaces | where splunk_managed_lifecycle == \"PRESENT\" \n    | mvexpand AdapterUnit.ExtEthIfs.Parent.Moid  \n    | rename Name AS VNIC \n    | rename AdapterUnit.AdapterId as Network_Adapter\n    | rename VifId as Virtual_Circuit\n    | rename Vethernet.NetworkElement.SwitchId as SwitchId\n    | rename Vethernet.BoundInterface.PortChannelId as PortChannelId\n    | eval FI_Uplink = if(\n       isnotnull('Vethernet.PinnedInterface.SlotId') AND isnotnull('Vethernet.PinnedInterface.PortId'),\n       'Vethernet.PinnedInterface.SlotId' . \"/\" . 'Vethernet.PinnedInterface.PortId',\n       mvindex(split('Vethernet.PinnedInterfaceDn', \"/\"), -1)\n    )\n    | eval FC_Server_Interface=if(isnotnull(PortChannelId), \"PC-\" + PortChannelId, null())\n    | table _key, PortId, Dn, OperSpeed, OperState, Role, SwitchId, Server_Moid, Server_Name, Model, PlatformType, VNIC, Virtual_Circuit, Network_Adapter, FI_Uplink, FC_Server_Interface\n]\n]\n\n| where \"false\"=\"true\" OR (total_nitsag != 0)\n\n| eval Utilization = `cisco_intersight_human_readable_bytes(total_nitsag)`.\" \".`cisco_intersight_human_readable_unit(total_nitsag)`\n\n| rename server_name as \"Server Name\", \n         cisco_intersight.cisco_intersight_network.network_chassis_number as \"Chassis Number\", \n         cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\", \n         server_profile_name as \"Server Profile Name\", \n         cisco_intersight.cisco_intersight_network.network_server_id as _hwServerId,\n         cisco_intersight.cisco_intersight_network.network_name as Name, \n        cisco_intersight.cisco_intersight_network.network_port_role as \"Port Role\"\n\n| where isnotnull(Virtual_Circuit) OR isnotnull(Network_Adapter) OR isnotnull(FI_Uplink) OR isnotnull(IOM_Host_Interface) OR isnotnull(FC_Server_Interface)\n\n| table \"Domain Name\", \"Chassis Number\", \"Server Profile Name\", \"Server Name\", Name, Utilization, Dn, OperSpeed, OperState, SwitchId, Virtual_Circuit, Network_Adapter, OperState, FI_Uplink, IOM_Host_Interface, FC_Server_Interface, _hwServerId\n",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
