            "name": "Errors per selected port_ __clicked_errors_name_server__ search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_receive_discard_error_sum) as enrds\n    sum(cisco_intersight.cisco_intersight_network.network_too_short_error_sum) as enrtss\n    sum(cisco_intersight.cisco_intersight_network.network_no_buffer_sum) as enrnbs\n    sum(cisco_intersight.cisco_intersight_network.network_crc_duration_sum) as ncrccs\n    sum(cisco_intersight.cisco_intersight_network.network_too_long_error_sum) as enrtls\n    sum(cisco_intersight.cisco_intersight_network.network_runt_error_sum) as nrrs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_jabber_error_sum) as entjs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_discard_error_sum) as entds\n    sum(cisco_intersight.cisco_intersight_network.network_carrier_sense_error_sum) as encss\n    sum(cisco_intersight.cisco_intersight_network.network_late_collisions_error_sum) as enlcs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_deferred_error_sum) as entdfs\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_id=$clicked_errors_server$\n    by _time\n\n| eval enrds=coalesce(enrds, 0),\n       enrtss=coalesce(enrtss, 0),\n       enrnbs=coalesce(enrnbs, 0),\n       ncrccs=coalesce(ncrccs, 0),\n       enrtls=coalesce(enrtls, 0),\n       nrrs=coalesce(nrrs, 0),\n       entjs=coalesce(entjs, 0),\n       entds=coalesce(entds, 0),\n       encss=coalesce(encss, 0),\n       enlcs=coalesce(enlcs, 0),\n       entdfs=coalesce(entdfs, 0)\n\n| $granularity$ \n    sum(enrds) as \"Receive Discard\",\n    sum(enrtss) as \"Too Short\",\n    sum(enrnbs) as \"No Buffer\",\n    sum(ncrccs) as \"CRC\",\n    sum(enrtls) as \"Too Long\",\n    sum(nrrs) as \"Runt\",\n    sum(entjs) as \"Jabber\",\n    sum(entds) as \"Transmit Discard\",\n    sum(encss) as \"Carrier Sense\",\n    sum(enlcs) as \"Late Collision\",\n    sum(entdfs) as \"Transmit Deferred\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_cGpElpVV": {
            "name": "Select Server Profile search",
            "options": {
                "query": "| tstats values(cisco_intersight.cisco_intersight_network.network_server_id) as server_id\n  from datamodel=Cisco_Intersight \n  where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$), cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n  by cisco_intersight.cisco_intersight_network.network_domain_id, cisco_intersight.cisco_intersight_network.network_chassis, cisco_intersight.cisco_intersight_network.network_server_id, cisco_intersight.cisco_intersight_network.network_account_name\n\n| rex field=server_id \".*/(?<server_moid>[^/]+)$\"\n| dedup server_moid\n| join type=left server_moid [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\"\n| dedup AssignedServer.Moid\n| rename AssignedServer.Moid as server_moid | table server_moid, Name\n]\n| table event.hwChassis, server_moid, Name",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_esN0ocsU": {
            "name": "Ethernet Receive utilization per Server _Sum_ 2 search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_io_receive) as total_nirs \n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n        AND cisco_intersight.cisco_intersight_network.network_server_id=*\n        AND cisco_intersight.cisco_intersight_network.network_port_role=\"vnic\"\n    by cisco_intersight.cisco_intersight_network.network_server_id, cisco_intersight.cisco_intersight_network.network_domain_id, cisco_intersight.cisco_intersight_network.network_account_name\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \".*/(?<server_id>[^/]+)$\"\n\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\"\n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id server_name\n]\n\n| where \"$show_zero_values$\"=\"true\" OR (total_nirs != 0)\n\n| eval \"Receive ($data_unit_receive$)\" = `cisco_intersight_bytes_to_given_unit(total_nirs,$data_unit_receive$)`\n\n| sort server_name\n| rename server_name as \"Server Name\"\n| table \"Server Name\", \"Receive ($data_unit_receive$)\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_iIZs1sJ1": {
            "name": "Server Errors - Overview search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_receive_discard_error_sum) as enrds\n    sum(cisco_intersight.cisco_intersight_network.network_too_short_error_sum) as enrtss\n    sum(cisco_intersight.cisco_intersight_network.network_no_buffer_sum) as enrnbs\n    sum(cisco_intersight.cisco_intersight_network.network_crc_duration_sum) as ncrccs\n    sum(cisco_intersight.cisco_intersight_network.network_too_long_error_sum) as enrtls\n    sum(cisco_intersight.cisco_intersight_network.network_runt_error_sum) as nrrs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_jabber_error_sum) as entjs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_discard_error_sum) as entds\n    sum(cisco_intersight.cisco_intersight_network.network_carrier_sense_error_sum) as encss\n    sum(cisco_intersight.cisco_intersight_network.network_late_collisions_error_sum) as enlcs\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_deferred_error_sum) as entdfs\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis IN ($select_chassis$)\n        AND NOT cisco_intersight.cisco_intersight_network.network_port_role IN (\"unconfigured\", \"server_pc\", \"fabric_pc\", \"host_pc\", \"vethernet\", \"vfc\", \"eth_uplink_pc\")\n        AND cisco_intersight.cisco_intersight_network.network_name=\"*$errors_port_name_server$*\"\n    by \n        cisco_intersight.cisco_intersight_network.network_domain_name,\n        cisco_intersight.cisco_intersight_network.network_host_name,\n        cisco_intersight.cisco_intersight_network.network_port_role,\n        cisco_intersight.cisco_intersight_network.network_name,\n        cisco_intersight.cisco_intersight_network.network_id,\n        cisco_intersight.cisco_intersight_network.network_chassis,\n        cisco_intersight.cisco_intersight_network.network_chassis_number,\n        cisco_intersight.cisco_intersight_network.network_server_id, cisco_intersight.cisco_intersight_network.network_account_name\n\n| where (\"$show_zero_values$\"=\"false\" \n   AND ((enrds != 0 AND isnotnull(enrds)) OR (enrtss != 0 AND isnotnull(enrtss)) OR (enrnbs != 0 AND isnotnull(enrnbs)) OR (ncrccs != 0 AND isnotnull(ncrccs)) OR (enrtls != 0 AND isnotnull(enrtls)) OR (nrrs != 0 AND isnotnull(nrrs)) OR (entjs != 0 AND isnotnull(entjs)) OR (entds != 0 AND isnotnull(entds)) OR (encss != 0 AND isnotnull(encss)) OR (enlcs != 0 AND isnotnull(enlcs)) OR (entdfs != 0 AND isnotnull(entdfs)))) OR (\"$show_zero_values$\"=\"true\" AND (isnotnull(enrds) OR isnotnull(enrtss) OR isnotnull(enrnbs) OR isnotnull(ncrccs) OR isnotnull(enrtls) OR isnotnull(nrrs) OR isnotnull(entjs) OR isnotnull(entds) OR isnotnull(encss) OR isnotnull(enlcs) OR isnotnull(entdfs)))\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \".*/(?<server_id>[^/]+)$\"\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id server_name\n]\n\n| join type=left server_id [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_profile_name by AssignedServer.Moid\n    | rename AssignedServer.Moid as server_id\n    | table server_id server_profile_name\n]\n\n| eval rx_sum = enrds + enrtss + enrnbs + ncrccs + enrtls + nrrs\n| eval tx_sum = entjs + entds + encss + enlcs + entdfs\n| eval total = rx_sum + tx_sum\n\n| rename nrrs as Runt, enrtls as \"Too Long\", enrnbs as \"No Buffer\", enrtss as \"Too Short\", enrds as \"Receive Discard\", entds as \"Transmit Discard\", entdfs as \"Transmit Deferred\", enlcs as \"Late Collision\", encss as \"Carrier Sense\", entjs as Jabber, ncrccs as CRC, \n         rx_sum as \"Receive Errors Sum\", tx_sum as \"Transmit Errors Sum\", total as \"Total Errors\",\n         cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\", \n         cisco_intersight.cisco_intersight_network.network_port_role as \"Network Port Role\", \n         cisco_intersight.cisco_intersight_network.network_name as \"Port Name\", \n         cisco_intersight.cisco_intersight_network.network_chassis_number as \"Chassis Number\",\n         server_name as \"Server Name\",\n         server_profile_name as \"Server Profile Name\",\n         cisco_intersight.cisco_intersight_network.network_id as _event_id\n\n| table \"Domain Name\", \"Chassis Number\", \"Server Profile Name\", \"Server Name\", \"Network Port Role\", \"Port Name\", \"Total Errors\", \"Receive Errors Sum\", \"Receive Discard\", \"Too Short\", \"No Buffer\", \"CRC\", \"Too Long\", \"Runt\", \"Transmit Errors Sum\", \"Jabber\", \"Transmit Discard\", \"Carrier Sense\", \"Late Collision\", \"Transmit Deferred\", _event_id",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_krywWCU1": {
            "name": "Ethernet Transmit utilization per Server _Sum__ _clicked_server_ethernet_receive_name_ search",
            "options": {
                "query": "| tstats \n    sum(cisco_intersight.cisco_intersight_network.network_io_receive_ag) as total_nirsag\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_server_id=$clicked_server_ethernet_transmit$\n        AND cisco_intersight.cisco_intersight_network.network_port_role=\"vnic\"\n    by _time, cisco_intersight.cisco_intersight_network.network_name, cisco_intersight.cisco_intersight_network.network_server_id\n\n| rex field=cisco_intersight.cisco_intersight_network.network_server_id \".*/(?<server_id>[^/]+)$\"\n| search server_id IN ($select_server$)\n\n| join type=left server_id [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" \n    | stats values(Name) as server_name by Moid\n    | rename Moid as server_id\n    | table server_id server_name\n]\n\n| rename cisco_intersight.cisco_intersight_network.network_name as Name\n| eval nirsag_mb = round(total_nirsag / 1024 / 1024, 2)\n| $granularity$ sum(nirsag_mb) as \"Utilization\" by Name",
